SELECT iw.hq_code as hqCode, ih.hq_name as hqName, iw.wp_code as wpCode, iw.wp_name as wpName, iw.user_company_code as userCompanyCode, iw.reg_ymd as regYmd, iw.status as status FROM IV_WORKPLACE iw LEFT JOIN IV_HEADQUARTERS ih ON iw.hq_code = ih.hq_code AND ( iw.user_company_code = ih.user_company_code OR (iw.user_company_code IS NULL AND ih.user_company_code IS NULL)) WHERE 1 = 1
AND iw.user_company_code = #{userCompanyCode}
AND iw.hq_code = #{hqCode}
AND iw.wp_code = #{wpCode}
AND iw.wp_name LIKE CONCAT('%', #{wpName}, '%')

SELECT hq_code as hqCode, wp_code as wpCode, wp_name as wpName, user_company_code as userCompanyCode, reg_ymd as regYmd, status as status FROM IV_WORKPLACE WHERE 1 = 1 AND wp_code = #{wpCode} AND hq_code = #{hqCode}
and user_company_code = #{userCompanyCode}
and user_company_code IS NULL

